from app.options_metrics.series import time_window_delta


def compute_series(ctx):
    base = ctx.option_metric_series('rr25')
    open_times = ctx.series('open_time')
    return time_window_delta(series=base, anchor_open_times_ms=open_times, horizon_ms=6 * 60 * 60 * 1000)

def compute_feature(step):
    is_settlement = step.feature_value('is_funding_settlement')
    bars_since = step.feature_value('bars_since_funding_settlement')
    if is_settlement is None or bars_since is None:
        return None
    return 1 if bool(is_settlement) or float(bars_since) <= 1 else 0

def compute_feature(step):
    bars_until = step.feature_value('bars_until_expiry')
    if bars_until is None:
        return None
    return 1 if float(bars_until) <= 2 else 0

def compute_series(ctx):
    close = ctx.series('close')
    returns = close.pct_change()
    return (returns - returns.rolling(24).mean()) / returns.rolling(24).std()

